[
  {
    "title": "Pretrained-Guided Conditional Diffusion Models for Microbiome Data Analysis",
    "authors": "Xinyuan Shi, Fangfang Zhu, Wenwen Min",
    "date": "2024-08-10 01:54:06+00:00",
    "abstract": "Emerging evidence indicates that human cancers are intricately linked to human microbiomes, forming an inseparable connection. However, due to limited sample sizes and significant data loss during collection for various reasons, some machine learning methods have been proposed to address the issue of missing data. These methods have not fully utilized the known clinical information of patients to enhance the accuracy of data imputation. Therefore, we introduce mbVDiT, a novel pre-trained conditional diffusion model for microbiome data imputation and denoising, which uses the unmasked data and patient metadata as conditional guidance for imputating missing values. It is also uses VAE to integrate the the other public microbiome datasets to enhance model performance. The results on the microbiome datasets from three different cancer types demonstrate the performance of our methods in comparison with existing methods...."
  },
  {
    "title": "DepMicroDiff: Diffusion-Based Dependency-Aware Multimodal Imputation for Microbiome Data",
    "authors": "Rabeya Tus Sadia, Qiang Cheng",
    "date": "2025-07-31 15:51:41+00:00",
    "abstract": "Microbiome data analysis is essential for understanding host health and disease, yet its inherent sparsity and noise pose major challenges for accurate imputation, hindering downstream tasks such as biomarker discovery. Existing imputation methods, including recent diffusion-based models, often fail to capture the complex interdependencies between microbial taxa and overlook contextual metadata that can inform imputation. We introduce DepMicroDiff, a novel framework that combines diffusion-based generative modeling with a Dependency-Aware Transformer (DAT) to explicitly capture both mutual pairwise dependencies and autoregressive relationships. DepMicroDiff is further enhanced by VAE-based pretraining across diverse cancer datasets and conditioning on patient metadata encoded via a large language model (LLM). Experiments on TCGA microbiome datasets show that DepMicroDiff substantially outperforms state-of-the-art baselines, achieving higher Pearson correlation (up to 0.712), cosine similarity (up to 0.812), and lower RMSE and MAE across multiple cancer types, demonstrating its robustness and generalizability for microbiome imputation...."
  }
]

[
  {
    "title": "Microbes in the Moonlight: How the Gut Microbiota Influences Sleep",
    "authors": "Enso Onill Torres Alegre",
    "date": "2025-11-04 17:50:49+00:00",
    "abstract": "The gut microbiota has emerged as a fundamental regulator of sleep physiology, influencing neural, endocrine, and immune pathways through the gut-microbiota-brain axis (GMBA). This bidirectional communication system modulates neurotransmitter production, circadian rhythms, and metabolic homeostasis, while disruptions in microbial composition have been linked to sleep disorders, neuroinflammation, and systemic immune dysfunction. Recent findings suggest that gut dysbiosis contributes to sleep disturbances by altering serotonin, GABA, and short-chain fatty acid (SCFA) metabolism, with implications for neurodegenerative diseases, metabolic syndromes, and mood disorders. Additionally, the gut microbiota interacts with the endocrine and immune systems, shaping inflammatory responses and stress adaptation mechanisms. This review explores the intricate connections between sleep and the gut microbiota, integrating emerging research on microbiota-targeted therapies, such as probiotics, fecal microbiota transplantation (FMT), and chrononutrition, as potential interventions to restore sleep homeostasis and improve health outcomes..."
  },
  {
    "title": "Assessing microbiome engraftment extent following fecal microbiota transplant with q2-fmt",
    "authors": "Chloe Herman, Evan Bolyen, Anthony Simard",
    "date": "2024-11-26 21:32:53+00:00",
    "abstract": "We present q2-fmt, a QIIME 2 plugin that provides diverse methods for assessing the extent of microbiome engraftment following fecal microbiota transplant. The methods implemented here were informed by a recent literature review on approaches for assessing FMT engraftment, and cover aspects of engraftment including Chimeric Asymmetric Community Coalescence, Donated Microbiome Indicator Features, and Temporal Stability. q2-fmt is free for all use, and detailed documentation illustrating worked examples on a real-world data set are provided in the project's documentation...."
  },
  {
    "title": "Statistical Methods for Microbiome Analysis: A brief review",
    "authors": "M. Bhattacharjee",
    "date": "2023-03-29 14:17:32+00:00",
    "abstract": "Recent attacks of various viruses with having deep and extensive impact at a global scale has warranted that microbiome be studied extensively and in a robust analytic framework. Microbiome typically refers to the collective genomes of such organisms, although it could also refer to the collection of the organisms by themselves. Here we provide an overview of statistical techniques that are useful in analysing such data...."
  },
  {
    "title": "Metagenomic analysis reveals shared and distinguishing features in horse and donkey gut microbiome and maternal resemblance of the microbiota in hybrid equids",
    "authors": "Yihang Zhou",
    "date": "2024-07-06 13:37:11+00:00",
    "abstract": "Mammalian gut microbiomes are essential for host functions like digestion, immunity, and nutrient utilization. This study examines the gut microbiome of horses, donkeys, and their hybrids, mules and hinnies, to explore the role of microbiomes in hybrid vigor. We performed whole-genome sequencing on rectal microbiota from 18 equids, generating detailed microbiome assemblies. Our analysis revealed significant differences between horse and donkey microbiomes, with hybrids showing a pronounced maternal resemblance. Notably, Firmicutes were more abundant in the horse-maternal group, while Fibrobacteres were richer in the donkey-maternal group, indicating distinct digestive processes. Functional annotations indicated metabolic differences, such as protein synthesis in horses and energy metabolism in donkeys. Machine learning predictions of probiotic species highlighted potential health benefits for each maternal group. This study provides a high-resolution view of the equid gut microbiome, revealing significant taxonomic and metabolic differences influenced by maternal lineage, and offers insights into microbial contributions to hybrid vigor...."
  },
  {
    "title": "Large Motion Video Autoencoding with Cross-modal Video VAE",
    "authors": "Yazhou Xing, Yang Fei, Yingqing He",
    "date": "2024-12-23 18:58:24+00:00",
    "abstract": "Learning a robust video Variational Autoencoder (VAE) is essential for reducing video redundancy and facilitating efficient video generation. Directly applying image VAEs to individual frames in isolation can result in temporal inconsistencies and suboptimal compression rates due to a lack of temporal compression. Existing Video VAEs have begun to address temporal compression; however, they often suffer from inadequate reconstruction performance. In this paper, we present a novel and powerful video autoencoder capable of high-fidelity video encoding. First, we observe that entangling spatial and temporal compression by merely extending the image VAE to a 3D VAE can introduce motion blur and detail distortion artifacts. Thus, we propose temporal-aware spatial compression to better encode and decode the spatial information. Additionally, we integrate a lightweight motion compression model for further temporal compression. Second, we propose to leverage the textual information inherent in text-to-video datasets and incorporate text guidance into our model. This significantly enhances reconstruction quality, particularly in terms of detail preservation and temporal stability. Third, we further improve the versatility of our model through joint training on both images and videos, which not only enhances reconstruction quality but also enables the model to perform both image and video autoencoding. Extensive evaluations against strong recent baselines demonstrate the superior performance of our method. The project website can be found at~\\href{https://yzxing87.github.io/vae/}{https://yzxing87.github.io/vae/}...."
  },
  {
    "title": "Energy-Calibrated VAE with Test Time Free Lunch",
    "authors": "Yihong Luo, Siya Qiu, Xingjian Tao",
    "date": "2023-11-07 15:35:56+00:00",
    "abstract": "In this paper, we propose a novel generative model that utilizes a conditional Energy-Based Model (EBM) for enhancing Variational Autoencoder (VAE), termed Energy-Calibrated VAE (EC-VAE). Specifically, VAEs often suffer from blurry generated samples due to the lack of a tailored training on the samples generated in the generative direction. On the other hand, EBMs can generate high-quality samples but require expensive Markov Chain Monte Carlo (MCMC) sampling. To address these issues, we introduce a conditional EBM for calibrating the generative direction of VAE during training, without requiring it for the generation at test time. In particular, we train EC-VAE upon both the input data and the calibrated samples with adaptive weight to enhance efficacy while avoiding MCMC sampling at test time. Furthermore, we extend the calibration idea of EC-VAE to variational learning and normalizing flows, and apply EC-VAE to an additional application of zero-shot image restoration via neural transport prior and range-null theory. We evaluate the proposed method with two applications, including image generation and zero-shot image restoration, and the experimental results show that our method achieves competitive performance over single-step non-adversarial generation. Our code is available at https://github.com/DJ-LYH/EC-VAE...."
  },
  {
    "title": "Simple and Effective VAE Training with Calibrated Decoders",
    "authors": "Oleh Rybkin, Kostas Daniilidis, Sergey Levine",
    "date": "2020-06-23 17:57:47+00:00",
    "abstract": "Variational autoencoders (VAEs) provide an effective and simple method for modeling complex distributions. However, training VAEs often requires considerable hyperparameter tuning to determine the optimal amount of information retained by the latent variable. We study the impact of calibrated decoders, which learn the uncertainty of the decoding distribution and can determine this amount of information automatically, on the VAE performance. While many methods for learning calibrated decoders have been proposed, many of the recent papers that employ VAEs rely on heuristic hyperparameters and ad-hoc modifications instead. We perform the first comprehensive comparative analysis of calibrated decoder and provide recommendations for simple and effective VAE training. Our analysis covers a range of image and video datasets and several single-image and sequential VAE models. We further propose a simple but novel modification to the commonly used Gaussian decoder, which computes the prediction variance analytically. We observe empirically that using heuristic modifications is not necessary with our method. Project website is at https://orybkin.github.io/sigma-vae/..."
  },
  {
    "title": "Rough Set Microbiome Characterisation",
    "authors": "Benjamin Wingfield, Sonya Coleman, T. M. McGinnity",
    "date": "2021-05-09 10:35:05+00:00",
    "abstract": "Microbiota profiles measure the structure of microbial communities in a defined environment (known as microbiomes). In the past decade, microbiome research has focused on health applications as a result of which the gut microbiome has been implicated in the development of a broad range of diseases such as obesity, inflammatory bowel disease, and major depressive disorder. A key goal of many microbiome experiments is to characterise or describe the microbial community. High-throughput sequencing is used to generate microbiota profiles, but data gathered via this method are extremely challenging to analyse, as the data violate multiple strong assumptions of standard models. Rough Set Theory (RST) has weak assumptions that are less likely to be violated, and offers a range of attractive tools for extracting knowledge from complex data. In this paper we present the first application of RST for characterising microbiomes. We begin with a demonstrative benchmark microbiota profile and extend the approach to gut microbiomes gathered from depressed subjects to enable knowledge discovery. We find that RST is capable of excellent characterisation of the gut microbiomes in depressed subjects and identifying previously undescribed alterations to the microbiome-gut-brain axis. An important aspect of the application of RST is that it provides a possible solution to an open research question regarding the search for an optimal normalisation approach for microbiome census data, as one does not currently exist...."
  },
  {
    "title": "Integration of multiview microbiome data for deciphering microbiome-metabolome-disease pathways",
    "authors": "Lei Fang, Yue Wang, Chenglong Ye",
    "date": "2024-02-13 05:26:25+00:00",
    "abstract": "The intricate interplay between host organisms and their gut microbiota has catalyzed research into the microbiome's role in disease, shedding light on novel aspects of disease pathogenesis. However, the mechanisms through which the microbiome exerts its influence on disease remain largely unclear. In this study, we first introduce a structural equation model to delineate the pathways connecting the microbiome, metabolome, and disease processes, utilizing a target multiview microbiome data. To mitigate the challenges posed by hidden confounders, we further propose an integrative approach that incorporates data from an external microbiome cohort. This method also supports the identification of disease-specific and microbiome-associated metabolites that are missing in the target cohort. We provide theoretical underpinnings for the estimations derived from our integrative approach, demonstrating estimation consistency and asymptotic normality. The effectiveness of our methodologies is validated through comprehensive simulation studies and an empirical application to inflammatory bowel disease, highlighting their potential to unravel the complex relationships between the microbiome, metabolome, and disease...."
  },
  {
    "title": "Modelling the Distribution of 3D Brain MRI using a 2D Slice VAE",
    "authors": "Anna Volokitin, Ertunc Erdil, Neerav Karani",
    "date": "2020-07-09 13:23:15+00:00",
    "abstract": "Probabilistic modelling has been an essential tool in medical image analysis, especially for analyzing brain Magnetic Resonance Images (MRI). Recent deep learning techniques for estimating high-dimensional distributions, in particular Variational Autoencoders (VAEs), opened up new avenues for probabilistic modeling. Modelling of volumetric data has remained a challenge, however, because constraints on available computation and training data make it difficult effectively leverage VAEs, which are well-developed for 2D images. We propose a method to model 3D MR brain volumes distribution by combining a 2D slice VAE with a Gaussian model that captures the relationships between slices. We do so by estimating the sample mean and covariance in the latent space of the 2D model over the slice direction. This combined model lets us sample new coherent stacks of latent variables to decode into slices of a volume. We also introduce a novel evaluation method for generated volumes that quantifies how well their segmentations match those of true brain anatomy. We demonstrate that our proposed model is competitive in generating high quality volumes at high resolutions according to both traditional metrics and our proposed evaluation...."
  },
  {
    "title": "BDPM: A Machine Learning-Based Feature Extractor for Parkinson's Disease Classification via Gut Microbiota Analysis",
    "authors": "Bo Yu, Zhixiu Hua, Bo Zhao",
    "date": "2025-09-09 13:24:25+00:00",
    "abstract": "Background: Parkinson's disease remains a major neurodegenerative disorder with high misdiagnosis rates, primarily due to reliance on clinical rating scales. Recent studies have demonstrated a strong association between gut microbiota and Parkinson's disease, suggesting that microbial composition may serve as a promising biomarker. Although deep learning models based ongut microbiota show potential for early prediction, most approaches rely on single classifiers and often overlook inter-strain correlations or temporal dynamics. Therefore, there is an urgent need for more robust feature extraction methods tailored to microbiome data. Methods: We proposed BDPM (A Machine Learning-Based Feature Extractor for Parkinson's Disease Classification via Gut Microbiota Analysis). First, we collected gut microbiota profiles from 39 Parkinson's patients and their healthy spouses to identify differentially abundant taxa. Second, we developed an innovative feature selection framework named RFRE (Random Forest combined with Recursive Feature Elimination), integrating ecological knowledge to enhance biological interpretability. Finally, we designed a hybrid classification model to capture temporal and spatial patterns in microbiome data...."
  },
  {
    "title": "Habitat Fluctuations Drive Species Covariation in the Human Microbiota",
    "authors": "Charles K. Fisher, Thierry Mora, Aleksandra M. Walczak",
    "date": "2015-10-01 12:12:00+00:00",
    "abstract": "Two species with similar resource requirements respond in a characteristic way to variations in their habitat -- their abundances rise and fall in concert. We use this idea to learn how bacterial populations in the microbiota respond to habitat conditions that vary from person-to-person across the human population. Our mathematical framework shows that habitat fluctuations are sufficient for explaining intra-bodysite correlations in relative species abundances from the Human Microbiome Project. We explicitly show that the relative abundances of phylogenetically related species are positively correlated and can be predicted from taxonomic relationships. We identify a small set of functional pathways related to metabolism and maintenance of the cell wall that form the basis of a common resource sharing niche space of the human microbiota...."
  },
  {
    "title": "Social interaction, noise and antibiotic-mediated switches in the intestinal microbiota",
    "authors": "Vanni Bucci, Serena Bradde, Giulio Biroli",
    "date": "2012-03-13 18:05:39+00:00",
    "abstract": "The intestinal microbiota plays important roles in digestion and resistance against entero-pathogens. As with other ecosystems, its species composition is resilient against small disturbances but strong perturbations such as antibiotics can affect the consortium dramatically. Antibiotic cessation does not necessarily restore pre-treatment conditions and disturbed microbiota are often susceptible to pathogen invasion. Here we propose a mathematical model to explain how antibiotic-mediated switches in the microbiota composition can result from simple social interactions between antibiotic-tolerant and antibiotic-sensitive bacterial groups. We build a two-species (e.g. two functional-groups) model and identify regions of domination by antibiotic-sensitive or antibiotic-tolerant bacteria, as well as a region of multistability where domination by either group is possible. Using a new framework that we derived from statistical physics, we calculate the duration of each microbiota composition state. This is shown to depend on the balance between random fluctuations in the bacterial densities and the strength of microbial interactions. The singular value decomposition of recent metagenomic data confirms our assumption of grouping microbes as antibiotic-tolerant or antibiotic-sensitive in response to a single antibiotic. Our methodology can be extended to multiple bacterial groups and thus it provides an ecological formalism to help interpret the present surge in microbiome data...."
  },
  {
    "title": "Gut microbiome composition: back to baseline?",
    "authors": "Matthias M. Fischer, Matthias Bild",
    "date": "2019-06-27 11:08:39+00:00",
    "abstract": "In Nature Microbiology, Palleja and colleagues studied the changes in gut microbiome composition in twelve healthy men over a period of six months following an antibiotic intervention. The authors argued that the 'gut microbiota of the subjects recovered to near-baseline composition within 1.5 months' and only exhibited a 'mild yet long-lasting imprint following antibiotics exposure.' We here present a series of re-analyses of their original data which demonstrate a significant loss of microbial taxa even after the complete study period of 180 days. Additionally we show that the composition of the microbiomes after the complete study period only moderately correlates with the initial baseline states. Taken together with the lack of significant compositional differences between day 42 and day 180, we think that these findings suggest the convergence of the microbiomes to another stable composition, which is different from the pre-treatment states, instead of a recovery of the baseline state. Given the accumulating evidence of the role of microbiome perturbations in a variety of infectious and non-infectious diseases, as well as the crucial role antibiotics play in modern medicine, we consider these differences in compositional states worthy of further investigation...."
  },
  {
    "title": "Bayesian-Guided Generation of Synthetic Microbiomes with Minimized Pathogenicity",
    "authors": "Nisha Pillai, Bindu Nanduri, Michael J Rothrock",
    "date": "2024-04-29 21:30:30+00:00",
    "abstract": "Synthetic microbiomes offer new possibilities for modulating microbiota, to address the barriers in multidtug resistance (MDR) research. We present a Bayesian optimization approach to enable efficient searching over the space of synthetic microbiome variants to identify candidates predictive of reduced MDR. Microbiome datasets were encoded into a low-dimensional latent space using autoencoders. Sampling from this space allowed generation of synthetic microbiome signatures. Bayesian optimization was then implemented to select variants for biological screening to maximize identification of designs with restricted MDR pathogens based on minimal samples. Four acquisition functions were evaluated: expected improvement, upper confidence bound, Thompson sampling, and probability of improvement. Based on each strategy, synthetic samples were prioritized according to their MDR detection. Expected improvement, upper confidence bound, and probability of improvement consistently produced synthetic microbiome candidates with significantly fewer searches than Thompson sampling. By combining deep latent space mapping and Bayesian learning for efficient guided screening, this study demonstrated the feasibility of creating bespoke synthetic microbiomes with customized MDR profiles...."
  }
]

[
  {
    "title": "VTrans: A VAE-Based Pre-Trained Transformer Method for Microbiome Data Analysis",
    "authors": "Xinyuan Shi, Fangfang Zhu, Wenwen Min",
    "date": 2025,
    "abstract": "Predicting the survival outcomes and assessing the risk of patients play a pivotal role in comprehending the microbial composition across various stages of cancer. With the ongoing advancements in deep learning, it has been substantiated that deep learning holds the potential to analyze patient survival risks based on microbial data. However, confronting a common challenge in individual cancer datasets involves the limited sample size and the high dimensionality of the feature space. This predicament often leads to overfitting issues in deep learning models, hindering their ability to effectively extract profound data representations and resulting in suboptimal model performance. To overcome these challenges, we advocate the utilization of pretraining and fine-tuning strategies, which have proven effective in addressing the constraint of having a smaller sample size in individual cancer datasets. In this study, we propose a deep learning model that amalgamates Transformer encoder and variational autoencoder (VAE), VTrans, employing both pre-training and fine-tuning strategies to predict the survival risk of cancer patients using microbial data. Furthermore, we highlight the potential of extending VTrans to integrate microbial multi-omics data. Our method is assessed on three distinct cancer datasets from The Cancer Genome Atlas Program, and the research findings demonstrated that (1) VTrans excels in terms of performance compared to conventional machine learning and other deep learning models. (2) The utilization of pretraning significantly enhances its performance. (3) In contrast to positional encoding, employing VAE encoding proves to be more effective in enriching data representation. (4) Using the idea of saliency map, it is possible to observe which microbes have a high contribution to the classification results. These results demonstrate the effectiveness of VTrans in prediting patient survival risk. Source code and all datasets used in this paper are available at https://github.com/wenwenmin/VTrans and https://doi.org/10.5281/zenodo.14166580...."
  },
  {
    "title": "Comparison of Respiratory Microbiome Disruption Indices to Predict VAP and VAE risk at LTACH Admission",
    "authors": "Erik L. Clarke, K. Chiotos, James J Harrigan",
    "date": 2020,
    "abstract": "Background: Healthcare exposure results in significant microbiome disruption, particularly in the setting of critical illness, which may contribute to risk for healthcare-associated infections (HAIs). Patients admitted to long-term acute-care hospitals (LTACHs) have extensive prior healthcare exposure and critical illness; significant microbiome disruption has been previously documented among LTACH patients. We compared the predictive value of 3 respiratory tract microbiome disruption indices—bacterial community diversity, dominance, and absolute abundance—as they relate to risk for ventilator-associated pneumonia (VAP) and adverse ventilator-associated events (VAE), which commonly complicate LTACH care. Methods: We enrolled 83 subjects on admission to an academic LTACH for ventilator weaning and performed longitudinal sampling of endotracheal aspirates, followed by 16S rRNA gene sequencing (Illumina HiSeq), bacterial community profiling (QIIME2) for diversity, and 16S rRNA quantitative PCR (qPCR) for total bacterial abundance. Statistical analyses were performed with R and Stan software. Mixed-effects models were fit to relate the admission MDIs to subsequent clinically diagnosed VAP and VAE. Results: Of the 83 patients, 19 had been diagnosed with pneumonia during the 14 days prior to LTACH admission (ie, “recent past VAP”); 23 additional patients were receiving antibiotics consistent with empiric VAP therapy within 48 hours of admission (ie, “empiric VAP therapy”); and 41 patients had no evidence of VAP at admission (ie, “no suspected VAP”). We detected no statistically significant differences in admission Shannon diversity, maximum amplicon sequence variant (ASV)–level proportional abundance, or 16S qPCR across the variables of interest. In isolation, all 3 admission microbiome disruption indices showed poor predictive performance, though Shannon diversity performed better than maximum ASV abundance. Predictive models that combined (1) bacterial diversity or abundance with (2) recent prior VAP diagnosis and (3) concurrent antibiotic exposure best predicted 14-day VAP (type S error < 0.05) and 30-day VAP (type S error < 0.003). In this cohort, VAE risk was paradoxically associated with higher admission Shannon diversity and lower admission maximum ASV abundance. Conclusions: In isolation, respiratory tract microbiome disruption indices obtained at LTACH admission showed poor predictive performance for subsequent VAP and VAE. But diversity and abundance models incorporating recent VAP history and admission antibiotic exposure performed well predicting 14-day and 30-day VAP. Disclosures: None Funding: None..."
  },
